import "./slider.css";

import { Slider } from "radix-ui";
import { cn } from "tailwind-variants";

import { sliderVariants } from "./slider.variants";

export type SliderProps = React.ComponentProps<typeof Slider.Root>;

export const SliderRoot = ({ className, ...props }: SliderProps) => {
  const { range, root, thumb, track } = sliderVariants();

  return (
    <Slider.Root className={cn(root(), className)} {...props}>
      <Slider.Track className={track()}>
        <Slider.Range className={range()} />
      </Slider.Track>
      <Slider.Thumb className={thumb()} />
    </Slider.Root>
  );
};

import { tv, type VariantProps } from "tailwind-variants";

export const sliderVariants = tv({
  slots: {
    range: "slider__range",
    root: "slider",
    thumb: "slider__thumb",
    track: "slider__track",
  },
});

export type SliderVariants = VariantProps<typeof sliderVariants>;

.slider {
  @apply relative flex w-full touch-none items-center select-none;
}

.slider__track {
  @apply bg-primary/20 relative h-1.5 w-full grow overflow-hidden rounded-full;
}

.slider__range {
  @apply bg-primary absolute h-full;
}

.slider__thumb {
  @apply border-primary/50 bg-background block size-4 rounded-full border shadow transition-colors;

  &:hover {
    @apply bg-accent;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &:disabled {
    @apply pointer-events-none opacity-50;
  }
}

import { SliderRoot } from "./slider";

export const Slider = {
  Root: SliderRoot,
};

export { SliderRoot };

export { type SliderVariants, sliderVariants } from "./slider.variants";
